import { useEffect, useState } from 'react';
import StatCards from './components/StatCards.jsx';
import LogisticsGraph from './components/LogisticsGraph.jsx';
import OrderTable from './components/OrderTable.jsx';
import Carousel from './components/Carousel.jsx';
import Footer from './components/Footer.jsx';

function App() {
    const [orders, setOrders] = useState([]);
    const [logs, setLogs] = useState([]);
    const [isConnected, setIsConnected] = useState(false);

    useEffect(() => {
        const ws = new WebSocket('ws://localhost:8000/ws/orders');

        ws.onopen = () => setIsConnected(true);
        ws.onclose = () => setIsConnected(false);

        ws.onmessage = (event) => {
            try {
                const order = JSON.parse(event.data);
                setOrders((prev) => [order, ...prev]);
                setLogs((prev) => {
                    const entry = `[${new Date().toLocaleTimeString()}] - ORDER #${order.id?.slice(0, 8) ?? 'unknown'} - ${order.status} by ${order.carrier}`;
                    return [entry, ...prev].slice(0, 50);
                });
            } catch (err) {
                console.error('Invalid WS payload', err);
            }
        };

        ws.onerror = (err) => {
            console.error('WebSocket error', err);
            setIsConnected(false);
        };

        return () => ws.close();
    }, []);

    useEffect(() => {
        fetch('http://localhost:8000/orders')
            .then((res) => res.json())
            .then((data) => setOrders(data))
            .catch((err) => console.error('Failed to load orders', err));
    }, []);

    const sendTestOrder = () => {
        const payload = {
            product_name: 'Biryani Spice Mix',
            quantity: Math.floor(Math.random() * 8) + 1,
            status: ['Pending', 'Picked', 'Shipped', 'Delivered'][Math.floor(Math.random() * 4)],
            carrier: ['DHL', 'UPS', 'DPD'][Math.floor(Math.random() * 3)],
            urgency: Math.floor(Math.random() * 5) + 1,
            created_at: new Date().toISOString(),
        };

        fetch('http://localhost:8000/orders/simulate', {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify(payload),
        })
            .then((res) => res.json())
            .then((created) => {
                console.log('Simulated order created', created);
            })
            .catch((err) => console.error('Test order failed', err));
    };

    return (
        <div className="app-shell">
            <header className="topbar">
                <div>
                    <h1>Realtime Logistics Dashboard</h1>
                    <p className="status">WebSocket: {isConnected ? 'Connected' : 'Disconnected'}</p>
                </div>
                <div>
                    <button className="btn test-order" onClick={sendTestOrder}>
                        🚀 Send Test Order
                    </button>
                </div>
            </header>

            <main>
                <StatCards orders={orders} />
                <Carousel logs={logs} />
                <div className="content-grid">
                    <div className="panel">
                        <h2>Logistics Line Graph</h2>
                        <LogisticsGraph orders={orders} />
                    </div>
                    <div className="panel">
                        <h2>Live Orders</h2>
                        <OrderTable orders={orders} />
                    </div>
                </div>

                <section className="log-console">
                    <h2>Live Logistics Console</h2>
                    <div>
                        {logs.length === 0 && <p>No events yet. Simulate an order.</p>}
                        {logs.map((item, idx) => (
                            <p key={`${item}-${idx}`} className="console-line">
                                {item}
                            </p>
                        ))}
                    </div>
                </section>
            </main>

            <Footer />
        </div>
    );
}

export default App;
